I run into this issue all the time. Sometimes I can use `select_related` or `prefetch_related`. Sometimes I run lots of raw queries in a list endpoint, so I've developed a pattern to add additional information on list views.

```python
class ModelResource(Resource):

    ...

    def obj_get_list(self, bundle, **kwargs):
        objects = super(ModelResource, self).obj_get_list(bundle, **kwargs)
        self.obj_attach_extra_data(objects, request=bundle.request)
        return objects

    def obj_get(self, bundle, **kwargs):
        obj = super(ModelResource, self).obj_get(bundle, **kwargs)
        self.obj_attach_extra_data([obj], request=bundle.request)
        return obj

    def obj_attach_extra_data(self, objects, request=None, **kwargs):
        cursor = connection.cursor()
        # Fetch external data
        self._data = list(cursor.execute(...).fetchall())

    def attach_data(self, bundle):
        try:
            bundle.data['extra'] = self._data
        except AttributeError:
            bundle.data['extra'] = []
        
    def dehydrate(self, bundle):
        self.attach_data(bundle)

        ...

        return bundle
```

